import json
from datetime import date
from elasticsearch import Elasticsearch


def read_input(name):
    """Read input data from file"""

    file = open(name+".in", 'r')
    data = []
    for line in file:
        data.append(line)
        
    return [x.rstrip() for x in data]

def write_output(name, content):
    
    file = open(name+".out", "w")
    file.write(content)
    

def main():    
    #get the input from the standard input
    in1=read_input("in")

    es = Elasticsearch()
    
    #Create an index with id=data
    es.indices.create('index0', body={"settings": {"number_of_shards": 5}, "mappings":{"properties" : { "message":"text","tags":"text", "date":{ "type":"date" },"date_formatted" : { "type":"date" }}}} )

    #Store the current date
    today=str(date.today())
    print(today)
    
    for index in es.indices.get('*'):
        es.indices.delete(index)
        
    #Parse each line and add to elastic search server    
    for i in range (0, len(in1)):
        
        json_doc={}
            
        #Store message
        json_doc["message"]=in1[i]

        #Split it by comma and save it as list of words, tags, and dates.
        msg=in1[i].split(",")
        tags=[]
        for x in range (0 ,len(msg)):
            if msg[x][-2:]==":d":
                json_doc["date"]=msg[x]
                json_doc["date"] = msg[x][:-2] #get rid of :d in the message
                json_doc["date_formatted"]=json_doc["date"]
                
        for x in range (0 ,len(msg)):
            if  msg[x][-3:]==":t":
                 json_doc["tags"]=msg[x].split(":")[1]

        #Store date_formatted as datetime object
        try :
            date_format=int(json_doc["date"][:4])*365+ int(json_doc["date"][5:-2])*30 +  int(json_doc["date"][-2:]) 
        except:
            date_format=""
        
        json_doc["date_formatted"]=date_format
        #If tags is not null, split by comma and add to tags
        if len(tags)!=0 : 
            json_doc['tags'] = [tag.strip() for tag in msg[1].split(",") ]
       
        #Store it into index  'index0'  with id = data    
        es.index(index='data', doc_type='message', body=json_doc, id="data", refresh=True)

    #Search and print it
    resp = es.search(body={'query':{'match':{'message': 'some message'}}})
    
    print(resp['hits']['total'])
    
    
if __name__ == '__main__':
    main()